#[derive(Clone, Default, serde::Serialize, serde::Deserialize)]
#[pyclass(frozen, from_py_object)]
pub struct CrawlResult {
    /// The list of crawled pages.
    #[pyo3(get)]
    pub pages: Vec<CrawlPageResult>,
    /// The final URL after following redirects.
    #[pyo3(get)]
    pub final_url: String,
    /// The number of redirects followed.
    #[pyo3(get)]
    pub redirect_count: usize,
    /// Whether any page was skipped during crawling.
    #[pyo3(get)]
    pub was_skipped: bool,
    /// An error message, if the crawl encountered an issue.
    #[pyo3(get)]
    pub error: Option<String>,
    /// Cookies collected during the crawl.
    #[pyo3(get)]
    pub cookies: Vec<CookieInfo>,
    /// Normalized URLs encountered during crawling (for deduplication counting).
    #[pyo3(get)]
    pub normalized_urls: Vec<String>,
}

#[pymethods]
impl CrawlResult {
    #[must_use]
    #[pyo3(signature = (pages=None, final_url=None, redirect_count=None, was_skipped=None, cookies=None, normalized_urls=None, error=None))]
    #[new]
    pub fn new(
        pages: Option<Vec<CrawlPageResult>>,
        final_url: Option<String>,
        redirect_count: Option<usize>,
        was_skipped: Option<bool>,
        cookies: Option<Vec<CookieInfo>>,
        normalized_urls: Option<Vec<String>>,
        error: Option<String>,
    ) -> Self {
        Self {
            pages: pages.unwrap_or_default(),
            final_url: final_url.unwrap_or_default(),
            redirect_count: redirect_count.unwrap_or_default(),
            was_skipped: was_skipped.unwrap_or_default(),
            error,
            cookies: cookies.unwrap_or_default(),
            normalized_urls: normalized_urls.unwrap_or_default(),
        }
    }

    #[pyo3(signature = ())]
    pub fn unique_normalized_urls(&self) -> usize {
        let core_self = kreuzcrawl::CrawlResult {
            pages: self.pages.clone().into_iter().map(Into::into).collect(),
            final_url: self.final_url.clone(),
            redirect_count: self.redirect_count,
            was_skipped: self.was_skipped,
            error: self.error.clone(),
            cookies: self.cookies.clone().into_iter().map(Into::into).collect(),
            normalized_urls: self.normalized_urls.clone(),
        };
        core_self.unique_normalized_urls()
    }
}

